"""
mkt-original — Genesis chapters 33-35
Run: python3 scripts/zc-original-genesis-33-35.py

Key linguistic coverage:
- Ch 33: shachah seven times (v3) ANE diplomatic protocol; the four reconciliation verbs (v4);
  chanan grace-name for children (v5); minchah/birkhah cultic vocabulary (vv8,11);
  "face of God" Peniel echo (v10); Succoth/sukkot etymology (v17); shalem=safely/Shalem (v18);
  qesitah currency unit (v19); El Elohe Israel altar-name (v20)
- Ch 34: the four rapid rape verbs: ra'ah/laqach/shakab/anah (v2); dabeq/ahav/daber-al-lev
  covenantal love language applied after violation (v3); nevalah/lo-yiasseh-ken legal formula (v7);
  mirmah deception echo of ch27 (v13); mohar/mattan marriage commercial terms (v12);
  "third day" vulnerability motif (v25); akar/trouble vocabulary (v30)
- Ch 35: elohei-ha-nekhar/taher/chalap triad (v2) paralleling Sinai; khibbat-elohim divine terror (v5);
  Allon-Bakuth etymology (v8); El Shaddai covenant renewal (v11); matsevah+nesek+oil anointing (v14);
  Ben-Oni/Benjamin death-name/life-name contrast (v18); Rachel's tomb → Jer 31:15/Matt 2:18 (v19);
  Reuben's sin as power-claim (v22)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_ORIGINAL = {
  "33": {
    "1": """<p><strong>wayyiśśāʾ yaʿăqōḇ ʿênāyw wayyarʾ wĕhinnēh ʿēśāw bāʾ</strong> — "Jacob looked up and saw — behold, Esau coming." The <em>wĕhinnēh</em> (behold!) signals a dramatic reversal: Jacob has arranged his household by descending order of love (v2 — servants first, Rachel/Joseph last), placing those he loves most at the rear, the position of greatest protection. The division reflects Jacob's triage under fear: the loved ones are shielded by the expendable. The narrative does not editorialize; the arrangement speaks for itself.</p>""",
    "2": """<p><strong>wayyāśem ʾet-hašĕpāḥôt wĕʾet-yaldêhen bāriʾšōnāh wĕʾet-lēʾāh wĕyaldêhā ʾaḥărōnîm wĕʾet-rāḥēl wĕʾet-yôsēp ʾaḥărōnîm</strong> — "He put the servants and their children first, Leah and her children next, and Rachel and Joseph last." The ordering mirrors the inverse of Jacob's emotional priorities (29:30 — he loved Rachel more than Leah). To place someone last in a procession before an armed encounter is to place them furthest from danger. The twice-repeated <em>ʾaḥărōnîm</em> (last) for Rachel and Joseph emphasizes their protected position. This arrangement will recur in v6-7 as each group approaches and bows.</p>""",
    "3": """<p><strong>wĕhûʾ ʿāḇar lipnêhem wayyištaḥû ʾarṣāh šeḇaʿ pĕʿāmîm ʿaḏ-giššetô ʾel-ʾāḥîw</strong> — "He passed ahead of them, bowing to the ground seven times until he came near his brother." <em>Wayyištaḥû ʾarṣāh</em> (bowing to the ground) — <em>šāḥāh</em> (H7812, to bow down, prostrate oneself) is both the posture of worship before deity and of submission before royalty. Seven full prostrations (<em>šeḇaʿ pĕʿāmîm</em>) is the protocol of a vassal approaching a suzerain, confirmed by the Amarna diplomatic letters (14th c. BCE): "I have bowed seven times, on the stomach and back." In Gen 27:29 the blessing Jacob stole included "nations bow down to you"; now Jacob bows to the very brother he supplanted. The seven prostrations are a complete reversal of the stolen blessing.</p>""",
    "4": """<p><strong>wayyāraṣ ʿēśāw liqrāʾtô wayyĕḥabbĕqēhû wayyippōl ʿal-ṣawwārô wayyiššāqēhû wayyiḇkû</strong> — "Esau ran to meet him, and embraced him, and fell on his neck, and kissed him. And they wept." The four verbs — <em>rûṣ</em> (ran), <em>ḥābaq</em> (embraced), <em>nāšaq</em> (kissed), <em>bāḵāh</em> (wept) — form the only tetracolon of reunion in Genesis. The identical three-verb cluster (<em>rûṣ</em>/<em>ḥābaq</em>/<em>nāšaq</em>) appeared at Laban's greeting of Jacob in 29:13, but there the tears are absent; Esau's tears mark the emotion as genuine rather than political. Luke 15:20's description of the father who "ran and fell on his neck and kissed" his returning son uses the same gesture-vocabulary, suggesting the Esau-Jacob reunion is the narrative archetype Jesus draws on for the prodigal parable.</p>""",
    "5": """<p><strong>wayyiśśāʾ ʾet-ʿênāyw wayyarʾ ʾet-hannāšîm wĕʾet-hayyĕlāḏîm wayyōʾmer mî-ʾēlleh lāḵ wayyōʾmer hayyĕlāḏîm ʾăšer-ḥānān ʾĕlōhîm ʾet-ʿaḇdĕḵā</strong> — "Jacob said, 'The children God has graciously given your servant.'" The verb <em>ḥānan</em> (H2603, to be gracious, to show favor, to give as a gift of grace) — the root of the name <em>chen</em> (grace, favor) — is Jacob's theological attribution: these children are not an achievement of his own striving but a gift of divine grace. After twenty years in which Jacob's household was built through rivalry, deception, and labor, he presents his family to Esau with the vocabulary of undeserved gift. The address <em>ʿaḇdĕḵā</em> (your servant) continues the diplomatic humility of v3.</p>""",
    "6": """<p><strong>waṯṯiggašnāh hašĕpāḥôt hēnnāh wĕyaldêhen waṯṯišṯaḥăwênāh</strong> — "The female servants and their children came forward and bowed down." The approach sequence mirrors the procession order of v2 — servants first. The Hithpael of <em>šāḥāh</em> (<em>waṯṯišṯaḥăwênāh</em>, they prostrated themselves) is the same bow Jacob performed in v3. The entire household enacts the diplomatic submission Jacob modeled. The narrative records the bowing without dialogue; the servants have no named speech-act here.</p>""",
    "7": """<p><strong>waṯṯiggaš gam-lēʾāh wĕyaldêhā wayyišṯaḥăwû wĕʾaḥar niggaš yôsēp wĕrāḥēl wayyišṯaḥăwû</strong> — "Then Leah and her children came and bowed down. Last of all came Joseph and Rachel, and they bowed down." The sequential introduction — servants, then Leah's group, then Joseph and Rachel — is the reverse of social standing (Rachel is the beloved) and the reverse of birth order (Reuben was born first). The narrator preserves the emotional order of protection that Jacob established in vv1-2. Joseph, the last-born and most beloved (his name means "may God add"), is introduced last — a placement that will frame his role in the subsequent Joseph narrative.</p>""",
    "8": """<p><strong>maḥăneh hazzeh ʾăšer pāgāštî</strong> — "What is the meaning of all this camp I met?" The word <em>maḥăneh</em> (H4264, camp, company) — the same word Jacob used for his own camp in 32:2 (<em>Mahanaim</em>) and for Esau's approaching camp (32:8). Esau's inquiry prompts Jacob's language of gift in v8b: <em>limṣōʾ ḥēn bĕʿênê ʾăḏōnî</em> — "to find favor (<em>ḥēn</em>) in the eyes of my lord." The gift (<em>minḥāh</em>, H4503) is a cultic/tribute term — the same word for the cereal offering brought before deity in the Levitical system. Jacob has selected the tribute-vocabulary deliberately.</p>""",
    "9": """<p><strong>wayyōʾmer ʿēśāw yeš-lî rāḇ ʾāḥî yĕhî-lĕḵā ʾăšer-lāḵ</strong> — "Esau said, 'I have plenty, my brother. Keep what is yours.'" <em>Yeš-lî rāḇ</em> — "there is to me much/plenty." The word <em>rāḇ</em> (H7227, much, many, great) is Esau's self-assessment. Jacob will counter in v11 with <em>yeš-lî ḵōl</em> — "I have everything/all." The contrast is theologically significant: Esau has <em>rāḇ</em> (much) — abundance by human measure; Jacob has <em>ḵōl</em> (all) — a covenantal totality. The address <em>ʾāḥî</em> (my brother) — the first time Esau uses this word in the reconciliation — signals that he is ending the hostility of ch 27.</p>""",
    "10": """<p><strong>rāʾîtî pāneyḵā kirʾōt pĕnê ʾĕlōhîm waṯṯirṣēnî</strong> — "To see your face is like seeing the face of God, now that you have received me favorably." The comparison <em>kirʾōt pĕnê ʾĕlōhîm</em> (like seeing the face of God) is a direct echo of 32:30, where Jacob named the Peniel site <em>penî-ʾēl</em> because "I have seen God face to face and my life was preserved." To see a powerful figure whose acceptance you feared is existentially analogous to the theophanic encounter. The <em>minḥāh</em> Jacob presses on Esau functions as a tribute-offering brought before a potentially wrathful lord — the cultic register is intentional. <em>Waṯṯirṣēnî</em> (you have accepted me favorably, Qal imperfect of <em>rāṣāh</em>, H7521) — the same verb used for divine acceptance of offerings in Lev 1:4; 22:21.</p>""",
    "11": """<p><strong>qah-nāʾ ʾet-birḵātî ʾăšer hūḇāʾt lāḵ kî-ḥannannî ʾĕlōhîm wĕḵî yeš-lî-ḵōl</strong> — "Please accept my blessing (<em>birḵātî</em>) which is brought to you." <em>Birḵāh</em> (H1293, blessing) — the gift of animals is called Jacob's <em>birḵāh</em>. The word choice is striking: in 27:35 Isaac said to Esau "your brother came with deceit and took your blessing (<em>birḵāteḵā</em>)." Now Jacob names his tribute to Esau as <em>birḵātî</em> (my blessing). Whether Jacob is consciously returning what was stolen is not stated, but the narrative use of the same noun creates an interpretive frame. <em>ḵî ḥannannî ʾĕlōhîm</em> — "because God has been gracious to me" — the second use of <em>ḥānan</em> in this chapter (cf. v5), marking grace as the theological signature of Jacob's household narrative.</p>""",
    "12": """<p><strong>wayyōʾmer nisĕʿāh wĕnēlēḵāh wĕʾēlĕḵāh lĕnegdĕḵā</strong> — "Let us journey on, and I will go alongside you." Esau's proposal to accompany Jacob — <em>lĕnegdĕḵā</em> (before/alongside you) — is the gesture of a protective escort. Whether Esau's offer is magnanimous or carries a latent territorial dimension (escorting Jacob through his domain) is ambiguous. Jacob's response in vv13-14 declines politely; the subsequent action (v17) reveals that Jacob goes not toward Seir as promised, but to Succoth in the opposite direction.</p>""",
    "13": """<p><strong>hayyĕlāḏîm rakkîm wĕhаṣṣōʾn wĕhabbāqār ʿālôt ʿālāy</strong> — "The children are tender (<em>rakkîm</em>) and the nursing ewes and cows are a concern to me." <em>Rakkîm</em> (plural of <em>rakh</em>, H7390, tender, soft, delicate) — the same adjective applied to Leah's eyes in 29:17. Jacob uses the vulnerability of his children and animals as his pretext for travelling separately. The concern for the nursing animals (meyniqqot) reflects authentic pastoral knowledge — overdriving nursing stock for even one day risks their deaths.</p>""",
    "14": """<p><strong>yaʿăḇōr-nāʾ ʾăḏōnî lipnê ʿaḇdô wĕʾănî ʾetnahălāh lĕʾiṭṭî lĕregeḡ hammĕlāʾḵāh ʾăšer-lĕpānay</strong> — "Let my lord go ahead while I move slowly, at the pace of the work (<em>lĕregeḡ hamĕlāʾḵāh</em>) before me." <em>Regeḡ</em> (H7272, the foot/pace) — a late and rare term for "at the pace/step of"; the phrase <em>lĕregeḡ hamĕlāʾḵāh</em> means "at the step-rate of the livestock." The courtly address (<em>ʾăḏōnî</em>, my lord; <em>ʿaḇdô</em>, his servant) is sustained throughout — Jacob does not relax his deferential register even while arranging the separation. His stated destination in Seir is a narrative fiction; he goes to Succoth (v17).</p>""",
    "15": """<p><strong>wayyōʾmer ʿēśāw ʾaṣṣîḡāh-nāʾ ʿimmĕḵā minh-āʿām ʾăšer ʾittî wayyōʾmer lāmmāh zeh ʾemṣāʾ-ḥēn bĕʿênê ʾăḏōnî</strong> — "'Let me leave some of my men with you,' said Esau. 'Why should that be? Let me only find favor in my lord's eyes.'" Jacob's deflection — "why should that be?" — is gracious but firm. His use of <em>māṣāʾ ḥēn bĕʿênê ʾăḏōnî</em> (find favor in my lord's eyes) echoes the covenant-favor language of 6:8 (Noah found favor), 30:27 (Laban found favor through Jacob), and 32:5 (Jacob's own message to Esau). Jacob keeps his freedom of movement while closing the encounter with honor.</p>""",
    "16": """<p><strong>wayyāšāḇ bayyôm hahûʾ ʿēśāw lĕḏarkô śēʿîrāh</strong> — "So that day Esau returned on his way to Seir." The narrative's economy is stark: the anticipated armed encounter (32:7-8) resolves in a single chapter; Esau departs the narrative quietly. Jacob promised to come to Esau at Seir (v14); the narrative shows him going to Succoth instead (v17). Whether this is deliberate evasion or a planned delay that is never fulfilled, the narrator does not comment. The silence about Jacob's Seir-promise creates a moral ambiguity that the text neither resolves nor ignores.</p>""",
    "17": """<p><strong>wĕsukkōt ʿāśāh lô ḇāyit ûlĕmiqnēhû ʿāśāh sukkōt ʿal-kēn qārāʾ šēm-hammāqôm sukkôt</strong> — "He built a house for himself and made booths for his livestock; therefore the place is called Succoth." <em>Sukkôt</em> (H5523) — the toponym derived from <em>sukkōt</em> (H5521, booths/shelters, plural of <em>sukkāh</em>). The Feast of Booths (<em>Ḥag hasukkôt</em>) will commemorate Israel's wilderness wandering in booths (Lev 23:42-43); the settlement at Succoth in the Jordan valley (modern Tell Deir ʿAlla) is the first named settlement of Jacob's household in Canaan proper, and it is named for the agricultural/pastoral character of his construction rather than for a theophany — unlike virtually every other patriarchal place-name.</p>""",
    "18": """<p><strong>wayyāḇōʾ yaʿăqōḇ šālēm ʿîr šĕḵem ʾăšer bĕʾereṣ kĕnaʿan</strong> — "Jacob came safely (<em>šālēm</em>) to the city of Shechem." The word <em>šālēm</em> (H8003, complete, whole, unharmed) is a deliberate word-choice: it echoes <em>šālôm</em> (covenant peace/wholeness) and may also function as a proper noun — the ancient city name Shalem (cf. Ps 76:2, Salem = Jerusalem, city of Melchizedek). Jacob's arrival "in peace/wholeness" fulfills the vow condition of 28:21 ("if I return safely to my father's house"). The city of Shechem is the site of the first covenant meal with Canaanites (v20) — and the site of the violence that will follow in ch 34.</p>""",
    "19": """<p><strong>wayyiqen ʾet-ḥelqat haśśāḏeh ʾăšer nāṭāh-šām ʾohălô miyyaḏ bĕnê-ḥămôr ʾăḇî šĕḵem bĕmēʾāh qĕśîṭāh</strong> — "He bought the plot of ground where he pitched his tent from the sons of Hamor for a hundred <em>qĕśîṭāh</em>." <em>Qĕśîṭāh</em> (H7192) — a monetary unit of uncertain weight or composition, occurring only here, in Josh 24:32 (for the same Shechem plot, confirmed as Joseph's burial place), and in Job 42:11. The purchase legally grounds Jacob's household in Canaan — not merely as a sojourner camping with permission, but as a landowner with a purchased title. This plot will eventually contain Joseph's bones (Exod 13:19; Josh 24:32; Acts 7:16).</p>""",
    "20": """<p><strong>wayyaṣṣeḇ-šām mizḇēaḥ wayyiqrāʾ-lô ʾēl ʾĕlōhê yiśrāʾēl</strong> — "He erected an altar there and called it El Elohe Israel — God, the God of Israel." The altar-name <em>ʾēl ʾĕlōhê yiśrāʾēl</em> is a declaration: the God of the covenant is identified as the God of the man now named Israel. Jacob does not yet build the Bethel altar (that is commanded in 35:1); the Shechem altar is a spontaneous act of worship. The use of his new covenant name (Israel) in the altar's name is the first recorded instance of Jacob publicly using the Peniel identity. The naming pattern — "God is the God of Israel" — will become the covenant formula repeated throughout the OT (Exod 5:1; Josh 7:13; 2 Kgs 18:31).</p>"""
  },
  "34": {
    "1": """<p><strong>waṯṯēṣēʾ dînāh bat-lēʾāh ʾăšer yālaḏāh lĕyaʿăqōḇ liroot bĕḇĕnôt hāʾāreṣ</strong> — "Dinah went out to see (<em>lirʾōt</em>) the daughters of the land." The verb <em>yāṣāʾ</em> (to go out) combined with <em>rāʾāh</em> (to see) describes normal social mobility for a young woman — visiting female peers was customary. The narrator's use of <em>rāʾāh</em> (to see) is ironic: the following verse opens with Shechem "seeing" (<em>wayyarʾ</em>) her. The two seeings — Dinah's social seeing and Shechem's predatory seeing — are placed in immediate narrative juxtaposition. Dinah is identified by her maternal lineage (daughter of Leah) rather than the expected paternal lineage, perhaps emphasizing her position within the household hierarchy.</p>""",
    "2": """<p><strong>wayyarʾ ʾōtāh šĕḵem ben-ḥămôr haḥiwwî nĕśîʾ hāʾāreṣ wayyiqqaḥ ʾōtāh wayyiškaḇ ʾōtāh wayĕʿannehā</strong> — "When Shechem saw her, he took her and lay with her and violated her." Four verbs — <em>rāʾāh</em> (saw), <em>lāqaḥ</em> (took), <em>šāḵaḇ</em> (lay with), <em>ʿinnāh</em> — form a rapid sequence of predatory action. The Piel of <em>ʿānāh</em> (H6031) — to humble, afflict, violate by force — is the technical term for sexual violence in the legal and narrative texts (2 Sam 13:12,14,22,32 for Amnon's rape of Tamar; Deut 22:24,29). The word is not "seduced" or "took by persuasion" — the narrative's moral vocabulary is explicit. Shechem's title <em>nĕśîʾ hāʾāreṣ</em> (prince/ruler of the land) is a narrative detail: the one who commits the act is the one with the most social power to do it with impunity.</p>""",
    "3": """<p><strong>waṯṯiḏbaq napšô bĕḏînāh bat-yaʿăqōḇ wayyeʾĕhaḇ ʾet-hannaʿărāh wayyĕḏabbēr ʿal-lēḇ hannaʿărāh</strong> — "His soul clung to Dinah and he loved the young woman and spoke tenderly to her." Three phrases of attachment follow the rape: <em>dāḇaq</em> (H1692, to cling, cleave — the marriage-bonding verb of 2:24: "a man shall cleave to his wife"), <em>ʾāhaḇ</em> (loved), and <em>dāḇar ʿal-lēḇ</em> (spoke to the heart — the idiom for persuasive, intimate speech in Judg 19:3 [Levite to his concubine]; Isa 40:2 [God comforting Jerusalem]). The irony is structural: the language of covenantal love and bonding in Gen 2:24 is applied here to a relationship initiated by violence. The post-hoc attachment does not undo the act; the narrative refuses to allow the subsequent "love" to reframe the rape as seduction.</p>""",
    "4": """<p><strong>wayyōʾmer šĕḵem ʾel-ḥămôr ʾāḇîw lēʾmōr qah-lî ʾet-hayyaldāh hazzōʾt lĕʾiššāh</strong> — "Shechem said to his father Hamor, 'Get me this girl as my wife.'" The demand form — <em>qah-lî</em> (take for me, imperative of <em>lāqaḥ</em>, the same verb used for his taking of Dinah in v2) — treats the woman as an object of acquisition. The word <em>yaldāh</em> (girl, young woman, H3207) rather than <em>ʾiššāh</em> (woman) in the description but <em>ʾiššāh</em> in the desired outcome — "as my wife" — shows Shechem casting the relationship in legitimate marital terms without acknowledging what he has done. The transaction is directed to the father (Hamor), following ANE betrothal custom where the father negotiates.</p>""",
    "5": """<p><strong>wĕyaʿăqōḇ šāmaʿ kî ṭimmēʾ ʾet-dînāh bittô ûḇānāyw hāyû ʾet-miqnēhû baśśāḏeh wĕheḥĕrîš yaʿăqōḇ ʿaḏ-bōʾām</strong> — "Jacob heard that his daughter Dinah had been defiled (<em>ṭimmēʾ</em>), but he kept silent (<em>heḥĕrîš</em>) until his sons came home." <em>Ṭimmēʾ</em> (Piel of <em>ṭāmēʾ</em>, H2930, to defile, make impure) encompasses both moral and ritual impurity — the same root used for the holiness code's pollution categories. <em>Heḥĕrîš</em> (Hiphil of <em>ḥārash</em>, H2790, to be silent, to make no sound) — Jacob's silence contrasts sharply with his sons' fury in v7. The brothers' anger will be described as <em>ḥārāh</em> (v7); Jacob's words in v30 reveal his silence was prudential rather than moral — he was calculating the risk to himself.</p>""",
    "6": """<p><strong>wayyēṣēʾ ḥămôr ʾăḇî-šĕḵem ʾel-yaʿăqōḇ lĕḏabbēr ʾittô</strong> — "Hamor went out to Jacob to speak with him." The verbs of movement (<em>yāṣāʾ</em>, went out) and speech (<em>dāḇar</em>, to speak) frame the formal diplomatic encounter. Hamor approaches Jacob directly, bypassing the convention of allowing the woman's family to initiate. This puts Jacob in a reactive rather than active position — he must listen to Hamor's proposal before the brothers arrive. The narrator's pace slows at this point, anticipating the brothers' arrival and their deceptive counter-proposal.</p>""",
    "7": """<p><strong>wĕhēmmāh ḥārû wayyihar ʾănaššîm mĕʾōḏ kî nĕḇālāh ʿāśāh bĕyiśrāʾēl liškōḇ ʾet-bat-yaʿăqōḇ wĕḵēn lōʾ yēʿāśeh</strong> — "They were furious, for Shechem had committed an outrage (<em>nĕḇālāh</em>) in Israel — a thing that ought not to be done." <em>Nĕḇālāh</em> (H5039, disgrace, shameful folly, outrage) is a technical legal term for the most serious violations of social and moral order — used for Achan's sin (Josh 7:15), Amnon's rape of Tamar (2 Sam 13:12: "don't do this <em>nĕḇālāh</em>"), and sexual disorder in Judges 19:23-24. The accompanying formula <em>wĕḵēn lōʾ yēʿāśeh</em> (and so it ought not to be done) is a legal prohibition-formula signaling that the act constitutes a category violation. The phrase "in Israel" (<em>bĕyiśrāʾēl</em>) anticipates the people of Israel before the nation exists — projecting the tribal identity backward onto Jacob's household.</p>""",
    "8": """<p><strong>wayyĕḏabbēr ḥămôr ʾittām lēʾmōr šĕḵem bĕnî ḥāšĕqāh napšô bĕḇitteḵem</strong> — "My son Shechem — his soul longs for your daughter." <em>Ḥāšaq</em> (H2836, to long for, to be strongly attached to) is a rare verb expressing intense desire or bonding — used for YHWH's attachment to Israel in Deut 7:7 ("YHWH set his love on you") and 10:15 ("YHWH delighted in your fathers"). The verb frames Shechem's desire in the language of covenant-election love, which makes Hamor's proposal sound more compelling while obscuring the assault that initiated it. The diplomatic presentation of Shechem's desire as <em>ḥāšaq</em>-love is a rhetorical strategy.</p>""",
    "9": """<p><strong>wĕhitḥattĕnû ʾōtānû bĕnōtêḵem tittĕnû-lānû wĕʾet-bĕnōtênû tiqqĕḥû lāḵem</strong> — "Intermarry with us — give us your daughters, take our daughters for yourselves." <em>Hithḥatthēn</em> (Hithpael of <em>ḥātan</em>, H2859, to become related by marriage) — the verb for entering the covenant of marital alliance. In Deut 7:3 this specific verb is prohibited for Israel with Canaanite peoples: <em>lōʾ tithḥatthēn bām</em> (you shall not intermarry with them). Hamor's proposal is precisely what the Deuteronomic law will forbid — the assimilation of the covenant people into Canaanite social structure through intermarriage. The brothers' response is a refusal to assimilate, though their means of refusal (deception and massacre) is not commended.</p>""",
    "10": """<p><strong>wĕʾittānû tēšēḇû wĕhāʾāreṣ tihyeh lipnêḵem šĕḇû wĕsĕḥārûhā wĕhēʾāḥăzû ḇāh</strong> — "Dwell with us; the land is before you — live in it, trade in it, acquire property in it." Three verbs — <em>šāḇaṯ</em> (dwell), <em>sāḥar</em> (H5503, to go about trading, to trade/traffic), <em>ʾāḥaz</em> (H270, to seize, hold, acquire) — describe the economic integration being offered. <em>Sāḥar</em> (the merchant-verb) is from the same root as Issachar and the commercial vocabulary of Genesis 37-45. Hamor's offer is genuine assimilation — not merely marital but economic and territorial. The phrase "the land is before you" (<em>hāʾāreṣ tihyeh lipnêḵem</em>) echoes the formulation YHWH will use for the promised land.</p>""",
    "11": """<p><strong>wayyōʾmer šĕḵem ʾel-ʾāḇîhā wĕʾel-ʾaḥêhā ʾemṣāʾ-ḥēn bĕʿênêḵem wĕʾăšer tōʾmĕrû ʾēlāy ʾettēn</strong> — "Let me find favor (<em>ḥēn</em>) in your eyes, and I will give whatever you say." Shechem appropriates the covenantal favor-language Jacob used before Esau (32:5; 33:8,10,15) and that Jacob had used before Laban (30:27). <em>Māṣāʾ ḥēn bĕʿênê</em> (to find grace/favor in the eyes of) is the formula of covenantal petition — seeking the acceptance of a greater party by a lesser. Shechem's adoption of this formula positions him as the suppliant; the irony is that he violated the very person in whose family he is now seeking inclusion.</p>""",
    "12": """<p><strong>harḇû ʿālay mĕʾōḏ môhar ûmattān wĕʾettĕnāh kaʾăšer tōʾmĕrû ʾēlāy ûtĕnû-lî ʾet-hannaʿărāh lĕʾiššāh</strong> — "Make the bride-price and gift very high — I will pay whatever you say." <em>Môhar</em> (H4119, bride-price) — the payment made by the groom's family to the bride's family, establishing the legal transfer of the woman into marriage. <em>Mattān</em> (H4976, gift) — an additional gift, perhaps to the bride herself. Shechem's willingness to pay any price reveals both his desire and his family's wealth; it also signals that the subsequent circumcision-demand is within reach for a wealthy household. The commercial vocabulary of marriage negotiation is explicit here — marriage as legal-economic transaction.</p>""",
    "13": """<p><strong>wayyaʿănû ḇĕnê-yaʿăqōḇ ʾet-šĕḵem wĕʾet-ḥămôr ʾāḇîw bĕmirmāh wayyĕḏabbĕrû ʾăšer ṭimmēʾ ʾēt dînāh ʾăḥōtām</strong> — "Jacob's sons answered Shechem and his father Hamor with deceit (<em>bĕmirmāh</em>)." <em>Mirmāh</em> (H4820, deceit, treachery) — the same word used for Jacob's own deceit of Isaac in 27:35: "your brother came <em>bĕmirmāh</em> and took your blessing." The narrator names the deception explicitly before describing the proposal, signaling that what follows is to be read as manipulation rather than covenant negotiation. The pattern of familial deception — Isaac deceived by Jacob, Jacob deceived by Laban, Shechem/Hamor deceived by Jacob's sons — runs through Genesis as a recurring moral motif without divine endorsement.</p>""",
    "14": """<p><strong>lōʾ nûḵal laʿăśōt haddāḇār hazzeh lātēt ʾet-ʾăḥōtênû lĕʾîš ʾăšer-lô ʿorlāh kî-ḥerpāh hîʾ lānû</strong> — "We cannot give our sister to a man who has a foreskin — that would be a disgrace (<em>ḥerpāh</em>) to us." <em>Ḥerpāh</em> (H2781, reproach, disgrace, public shame) — the same word Rachel used for barrenness (30:23: "God has taken away my reproach"). Circumcision as the boundary marker of covenant membership is deployed here as a deceptive demand — the brothers use the covenant sign as a weapon rather than as a genuine invitation to covenant inclusion. The irony is mordant: the sign of Abraham's covenant becomes the mechanism of its desecration.</p>""",
    "15": """<p><strong>bĕzōʾt niʾôt lāḵem ʾim tihyû ḵāmōnû lĕhimmōl lāḵem kol-zāḵār</strong> — "On this one condition we will agree with you — if you become like us by circumcising all your males." The condition is stated in terms of equivalence: <em>lĕhimmōl lāḵem</em> (to circumcise yourselves) and the goal "if you become like us" (<em>ḵāmōnû</em>). The brothers frame circumcision as the entry condition for covenant-community membership — which is its genuine theological meaning — but their purpose is not inclusion. The Niphal <em>niʾôt</em> (we will consent) from <em>ʾāwāh</em> (to desire, consent) marks their agreement as conditional and transactional.</p>""",
    "16": """<p><strong>wĕnāḇōʾ ʾittĕḵem wĕhāyînû lĕʿam ʾeḥāḏ</strong> — "We will come among you and become one people (<em>lĕʿam ʾeḥāḏ</em>)." The phrase <em>ʿam ʾeḥāḏ</em> (one people) — the goal of political assimilation. The covenant formula "one people" is the positive outcome of the brothers' deceptive negotiation. The narrator's reader, who has been told in v13 that this is <em>mirmāh</em>, knows this outcome will not be realized. The language of becoming "one people" will return in Ezra-Nehemiah's crisis of intermarriage and in the NT (Eph 2:14-15) as the actual theological reality in Christ.</p>""",
    "17": """<p><strong>wĕʾim-lōʾ tišmĕʿû ʾēlênû lāqaḥtî ʾet-bittênû wĕhālaḵnû</strong> — "If you do not listen to us, we will take our sister and go." The ultimatum employs <em>lāqaḥ</em> (take) — the same verb used for Shechem's taking of Dinah in v2. The brothers' threat mirrors the structure of Shechem's act: he took what was not given; they will take back what was taken. The rhetorical symmetry may be intentional — the narrative is structured around takings and counter-takings.</p>""",
    "18": """<p><strong>wayyîṭĕḇû diḇrêhem bĕʿênê ḥămôr ûḇĕʿênê šĕḵem ben-ḥămôr</strong> — "Their proposal seemed good in the eyes of Hamor and Shechem." The idiom <em>yāṭaḇ bĕʿênê</em> (to be good in the eyes of) is the standard formula for approval or assessment. Hamor and Shechem evaluate the proposal by the pleasure it brings Shechem and the commercial advantage it offers the city (v23: "will not their livestock become ours?"). The mutual evaluations — the brothers calculating deception (v13), the Shechemites calculating advantage (v23) — meet at the circumcision-covenant as the space where both groups believe they are getting what they want.</p>""",
    "19": """<p><strong>wĕlōʾ-ʾiḥar hannaʿar laʿăśôt haddāḇār kî ḥāpēṣ bĕḇat-yaʿăqōḇ wĕhûʾ niḵbāḏ mikkōl bêt ʾāḇîw</strong> — "The young man wasted no time doing it, for he delighted in Jacob's daughter; and he was the most honored (<em>niḵbāḏ</em>) in all his father's household." <em>Niḵbāḏ</em> (Niphal of <em>kāḇaḏ</em>, H3513, to be heavy/weighty/honored) — the most honored member of Hamor's household. The combination of social honor and emotional desire (<em>ḥāpēṣ</em>, H2654, delighted, took pleasure in) makes Shechem's compliance immediate. His haste and honor are both turned against him by the deception.</p>""",
    "20": """<p><strong>wayyāḇōʾ ḥămôr ûšĕḵem bĕnô ʾel-šaʿar ʿîrām wayyĕḏabbĕrû ʾel-ʾanĕšê ʿîrām lēʾmōr</strong> — "Hamor and his son Shechem came to the gate of their city and spoke to the men of their city." The city gate (<em>šaʿar</em>, H8179) was the civic assembly space and judicial forum in ANE cities — where elders sat, contracts were ratified, and legal cases adjudicated (cf. Ruth 4:1-12; Amos 5:12,15; Prov 31:23). Addressing the men at the gate is the formal civic mechanism for ratifying a community decision. Hamor and Shechem present the circumcision-covenant to the whole city.</p>""",
    "21": """<p><strong>hāʾănāšîm hāʾēlleh šĕlēmîm hēm ʾittānû wĕyēšĕḇû ḇāʾāreṣ wĕyisĕḥărû ḇāh wĕhāʾāreṣ hinněh raḥăḇat-yāḏayim lipnêhem</strong> — "These men are peaceable toward us. Let them live in the land and trade in it — the land is wide enough for them." <em>Šĕlēmîm</em> (peaceful, from <em>šālôm</em>) — Hamor describes Jacob's family as peaceable/covenant-friendly; the word ironically shares the root with the <em>šālēm</em> of 33:18 where Jacob arrived "safely." The commercial appeal (<em>yisĕḥărû</em>, to trade, same root as merchant) frames the proposal to the city in economic terms. The men of the city are convinced by the prospect of trade and land-sharing, not by love of Shechem.</p>""",
    "22": """<p><strong>ʾaḵ-bĕzōʾt yēʾōtû lānû hāʾănāšîm lāšeḇet ʾittānû lihyôt lĕʿam ʾeḥāḏ bĕhimmôl lānû kol-zāḵār</strong> — "Only on this condition will the men consent to live with us — to become one people, if every male among us is circumcised." The condition is presented as merely the procedural requirement for the commercial union. The city's acceptance of circumcision as a reasonable price for economic integration underscores that the sign of Abraham's covenant has been fully secularized in this negotiation — it is treated as a cultural adaptation for commercial advantage rather than as a covenant mark with theological content.</p>""",
    "23": """<p><strong>miqnēhem wĕqinyānām wĕkol-bĕhemtām halōʾ lānû hēm ʾaḵ nēʾôtāh lāhem wĕyēšĕḇû ʾittānû</strong> — "Won't their livestock, property, and all their animals become ours?" Hamor's commercial appeal to the city's men reveals the transaction's true logic: circumcision is the price for absorbing a wealthy pastoral clan. The rhetorical question (<em>halōʾ</em>) invites the men to calculate the economic benefit. This is the narrator's subtle indictment: both parties are transacting in bad faith — the brothers intending massacre, the Shechemites intending economic absorption.</p>""",
    "24": """<p><strong>wayyišmĕʿû ʾel-ḥămôr wĕʾel-šĕḵem bĕnô kol-yōṣĕʾê šaʿar ʿîrô wayyimmōlû kol-zāḵār</strong> — "All who went out of the city gate agreed with Hamor and Shechem, and every male was circumcised." The legal assembly (gate = civic forum) ratifies the decision unanimously. The mass circumcision of the city's males is presented as a collective civic act — one that will render every man in the city incapacitated on the third day (v25). The irony that the covenant sign of Israel becomes the mechanism of a city's destruction runs through the entire chapter.</p>""",
    "25": """<p><strong>wayhî bayyôm haššĕlîšî bihyôtām kōʾăḇîm wayyiqqĕḥû šĕnê ḇĕnê-yaʿăqōḇ šimʿôn wĕlēwî ʾăḥê dînāh ʾîš ḥarḇô wayyāḇōʾû ʿal-hāʿîr beṭaḥ</strong> — "On the third day, when they were in pain (<em>kōʾăḇîm</em>), two of Jacob's sons, Simeon and Levi, Dinah's brothers, took their swords and attacked the unsuspecting city." <em>Bayyôm haššĕlîšî</em> (on the third day) — the third day is a significant temporal marker throughout the OT: the day of accountability, of revelation, of reversal (cf. Gen 22:4 — Abraham's third-day arrival at Moriah; Hos 6:2 — "on the third day he will raise us up"). The pain (<em>kōʾeḇ</em>, H3510, anguish/pain) renders the entire male population defenseless. <em>Beṭaḥ</em> (H983, in security/unsuspecting) — the same word used for Israel's covenant-security promise when obedient (Lev 26:5; Deut 33:28); here it marks the city's vulnerability as the very security they were promised.</p>""",
    "26": """<p><strong>wĕʾet-ḥămôr wĕʾet-šĕḵem bĕnô hārĕgû lĕpî-ḥāreḇ wayyiqqĕḥû ʾet-dînāh mibbêt šĕḵem wayyēṣēʾû</strong> — "They killed Hamor and his son Shechem with the sword and took Dinah from Shechem's house and left." The inclusion of <em>wayyiqqĕḥû ʾet-dînāh</em> (they took Dinah) — using the same verb <em>lāqaḥ</em> as Shechem's taking in v2 — reframes the rescue as a counter-taking. The narrative throughout ch 34 is structured around <em>lāqaḥ</em> (take): Shechem took Dinah (v2), Jacob's sons took their swords (v25), they took Dinah back (v26), they took the city's livestock (v28). The tit-for-tat structure of taking frames the entire episode.</p>""",
    "27": """<p><strong>ḇĕnê yaʿăqōḇ bāʾû ʿal-haḥălālîm wayyāḇōzzû hāʿîr ʾăšer ṭimmĕʾû ʾăḥôtām</strong> — "The sons of Jacob came upon the dead and plundered the city that had defiled their sister." The narrator calls them <em>ḇĕnê yaʿăqōḇ</em> (sons of Jacob) rather than <em>ḇĕnê yiśrāʾēl</em> (sons of Israel) — the pre-covenant name, perhaps marking the action as falling short of covenant identity. <em>ḇāzaz</em> (H962, to plunder, spoil) — the verb of warfare plunder. The stated justification — "the city that defiled their sister" — applies the guilt of Shechem to the entire city, a collective attribution the text leaves morally unresolved.</p>""",
    "28": """<p><strong>ʾet-ṣōʾnām wĕʾet-bĕqārām wĕʾet-ḥămōrêhem wĕʾēt ʾăšer-bāʿîr wĕʾet-ʾăšer baśśāḏeh lāqāḥû</strong> — "Their flocks and herds and donkeys — whatever was in the city and in the field — they took." The comprehensive plunder — <em>ṣōʾn</em> (flocks), <em>bāqār</em> (cattle), <em>ḥămōr</em> (donkeys) — is the full pastoral inventory. The inventory formula (livestock + field) is standard for plunder descriptions in the OT warfare tradition (cf. Num 31:9; Josh 8:27). The magnitude of the plunder transforms a personal honor-crime into a war of conquest with its full economic consequences.</p>""",
    "29": """<p><strong>wĕʾet-kol-ḥêlām wĕʾet-kol-ṭappām wĕʾet-nĕšêhem šāḇû wayyāḇōzzû wĕʾēt kol-ʾăšer babbāyit</strong> — "All their wealth and all their children and their women they took captive, and they plundered everything in the houses." The taking of women and children as captives (<em>šāḇā</em>, H7617, to take captive) is a war practice the Deuteronomic law will regulate (Deut 20:14; 21:10-14). Jacob's explicit protest in v30 focuses on practical danger to his household, not on the moral dimensions of enslaving the survivors.</p>""",
    "30": """<p><strong>wayyōʾmer yaʿăqōḇ ʾel-šimʿôn wĕʾel-lēwî ʿăḵarttem ʾōtî lĕhabbîʾšenî bĕyōšēḇ hāʾāreṣ baKĕnaʿănî ûḇapperizzî</strong> — "Jacob said to Simeon and Levi, 'You have brought trouble on me (<em>ʿăḵarttem</em>) by making me odious (<em>lehabbîšenî</em>)…'" <em>ʿāḵar</em> (H5916, to trouble, to roil/disturb) — the same root as the name Achan (Josh 7:1) and the Valley of Achor; it means to trouble someone by stirring up difficulty that brings consequences. <em>Bahʾ</em> (Hiphil of <em>bāʾaš</em>, H887, to stink/make odious) — Jacob's concern is his reputation and the safety of his household among the Canaanites, not the justice or injustice of the act. The contrast between Jacob's self-focused prudential concern (vv30) and the brothers' honor-defense (v31) is the moral fulcrum of the chapter.</p>""",
    "31": """<p><strong>wayyōʾmĕrû hăḵizonāh yaʿăśeh ʾet-ʾăḥōtênû</strong> — "Shall he treat our sister like a prostitute (<em>zônāh</em>)?" <em>Zônāh</em> (H2181, harlot, prostitute — Qal participle of <em>zānāh</em>, to commit sexual immorality) — the brothers' final word reframes Dinah's defilement through the honor-shame category of sexual availability to multiple men without covenant. In their logic, Shechem's act without marriage-covenant treated Dinah as a <em>zônāh</em> — a woman available outside covenant protection. The question-form of their closing statement is rhetorically unanswerable; Jacob's objection is not replied to. The narrative ends without resolving the competing claims — Jacob's safety, the brothers' honor, Dinah's silence.</p>"""
  },
  "35": {
    "1": """<p><strong>wayyōʾmer ʾĕlōhîm ʾel-yaʿăqōḇ qûm ʿălēh ḇêt-ʾēl wĕšeḇ-šām wĕʿăśēh-šām mizbēaḥ lāʾēl hannirʾeh ʾêleḵā bĕḇorḥăḵā mippĕnê ʿēśāw ʾāḥîḵā</strong> — "Go up to Bethel and settle there, and build an altar to God who appeared to you when you fled from your brother Esau." <em>ʿĂlēh</em> (Qal imperative of <em>ʿālāh</em>, to go up) — ascending to Bethel is an <em>ʿălîyāh</em> (ascent); Bethel is hill country above the Jordan valley. The description of God as <em>hannirʾeh ʾêleḵā bĕḇorḥăḵā</em> (who appeared to you when you were fleeing) recapitulates the Bethel theophany of ch 28 as the constitutive moment of Jacob's covenant relationship. The command comes after the violence of ch 34; the return to the altar is a covenant-renewal following moral contamination.</p>""",
    "2": """<p><strong>wayyōʾmer yaʿăqōḇ ʾel-bêtô wĕʾel kol-ʾăšer ʿimmô hāsirû ʾet-ʾĕlōhê hannēḵār ʾăšer bĕtōḵĕḵem wĕhiṭṭahărû wĕhahălîpû śimlōtêḵem</strong> — "Put away the foreign gods among you, purify yourselves, and change your garments." The triad — remove foreign gods (<em>ʾĕlōhê hannēḵār</em>, H5236, strange/foreign gods), purify (<em>ṭāhēr</em>, ritual purification), change garments (<em>ḥālaph śimlāh</em>) — is the preparation formula for meeting a holy God. The identical preparation is commanded before the Sinai theophany in Exod 19:10,14 (wash garments, consecrate). Jacob treats the ascent to Bethel as a holy-mountain approach requiring covenant purity. The foreign gods likely include those buried at the oak of Shechem (v4) and perhaps Rachel's household gods stolen from Laban (31:19).</p>""",
    "3": """<p><strong>wĕnāqûmāh wĕnaʿăleh bêt-ʾēl wĕʾeʿĕśeh-šām mizḇēaḥ lāʾēl hāʿōneh ʾōtî bĕyôm ṣārātî wĕhāyāh ʿimmādî baddereḵ ʾăšer hālaḵtî</strong> — "…the God who answered me in the day of my distress, who has been with me on the way I have gone." <em>Yôm ṣārātî</em> (day of my distress/straits) — <em>ṣārāh</em> (H6869, adversity, distress, tightness — from <em>ṣar</em>, narrow/constricted) describes the crisis of the Esau-pursuit. <em>Hāyāh ʿimmādî</em> (who was with me) — the fulfillment of the Bethel covenant promise: "I will be with you wherever you go" (28:15). Jacob's speech to his household is a covenant-history summary — this is how covenant memory works, connecting the present act of worship to the founding theophany.</p>""",
    "4": """<p><strong>wayyitĕnû ʾel-yaʿăqōḇ ʾēt kol-ʾĕlōhê hannēḵār ʾăšer bĕyāḏām wĕʾet-hannĕzāmîm ʾăšer bĕʾoznêhem wayyiṭmōn ʾōtām yaʿăqōḇ taḥat hāʾēlāh ʾăšer ʿim-šĕḵem</strong> — "They gave Jacob all the foreign gods and the rings in their ears, and Jacob buried them under the oak at Shechem." The earrings (<em>nĕzāmîm</em>, H5141, nose/ear rings) are associated with idolatrous worship — Exod 32:2-3: Aaron commanded the Israelites to remove their golden earrings to make the golden calf. The burial under the oak is a ritual interment — removing the gods from cultic accessibility. The oak at Shechem is the same tree (or its successor) under which Abraham stopped when he first entered Canaan (12:6). The disposal of the gods at the covenant-entry site is symbolically rich.</p>""",
    "5": """<p><strong>wayyisĕʿû wayhî ḥittat ʾĕlōhîm ʿal-hehārîm ʾăšer sĕḇîḇôtêhem wĕlōʾ rādĕpû ʾaḥărê bĕnê yaʿăqōḇ</strong> — "They set out, and a terror of God (<em>ḥittat ʾĕlōhîm</em>) fell on all the cities around them, so that no one pursued Jacob's sons." <em>Ḥittāh</em> (H2847, terror, panic, dread — from <em>ḥātat</em>, to be shattered/dismayed) combined with <em>ʾĕlōhîm</em> — a supernatural dread sent by God. This is the <em>ḥittāh</em> of holy-war tradition: YHWH sends panic/dread ahead of Israel (Exod 23:27-28: "I will send my terror ahead of you"; Deut 11:25: "the dread of you"). After the massacre of ch 34 that threatened to provoke Canaanite retaliation (33:30), the divine terror shields Jacob's household on the journey to Bethel. Covenant danger is met with covenant protection.</p>""",
    "6": """<p><strong>wayyāḇōʾ yaʿăqōḇ lûzāh ʾăšer bĕʾereṣ kĕnaʿan hîʾ bêt-ʾēl hûʾ wĕḵol-hāʿām ʾăšer-ʿimmô</strong> — "Jacob came to Luz in the land of Canaan — that is, Bethel — with all the people who were with him." The narrative provides the toponymic gloss: <em>Lûz</em> is the pre-Israelite name, <em>Bêt-ʾēl</em> the covenant name Jacob gave it in 28:19. The equivalence note occurs in 28:19 (at the naming), 35:6 (at the return), and will recur in Judg 1:23. The secular toponym and the sacred name coexist in the narrator's memory, preserving both layers of place-history.</p>""",
    "7": """<p><strong>wayyiḇen šām mizḇēaḥ wayyiqrāʾ lammāqôm ʾēl bêt-ʾēl kî šām niglû ʾēlāyw hāʾĕlōhîm bĕḇorḥô mippĕnê ʾāḥîw</strong> — "He built an altar and called the place El Bethel, because it was there that God was revealed to him when he fled from his brother." <em>Niglû</em> (Niphal of <em>gālāh</em>, H1540, to uncover, reveal, expose) — the passive of <em>gālāh</em> is used for divine self-revelation in the prophetic tradition (1 Sam 3:21; Isa 22:14; Jer 11:20). The altar-name <em>ʾēl bêt-ʾēl</em> (God of Bethel) is distinct from the place-name Bethel; Jacob names the place by what God did there, not merely by the place itself. The Niphal plural <em>niglû</em> (they were revealed) has puzzled commentators — perhaps indicating that multiple divine appearances occurred at Bethel (28:13; 31:13; 35:9), or reflecting a liturgical formula.</p>""",
    "8": """<p><strong>waṯṯāmāṯ debōrāh mêniqet ribqāh waṯṯiqqāḇēr miṯṯaḥat lĕḇêt-ʾēl taḥat hāʾallôn wayyiqrāʾ šĕmô ʾallôn bāḵût</strong> — "Deborah, Rebekah's nurse, died and was buried under the oak below Bethel, and the place was called Allon Bakuth." <em>Allôn bāḵût</em> = "oak of weeping" — <em>allôn</em> (H437, oak, terebinth) + <em>bāḵût</em> (H1068, weeping, from <em>bāḵāh</em>). Deborah traveled from Haran with Rebekah in 24:59 as her nurse (<em>mêniqet</em>, H3243, one who nurses/suckles). Her burial at Bethel — the covenant-renewal site — is noted without explanation. Some commentators suggest her death implicitly marks Rebekah's own death (whose death is never explicitly narrated in Genesis); both the nurse and the mother are absorbed into the Bethel transition. The named tree (<em>allôn</em>) will become a landmark for generations.</p>""",
    "9": """<p><strong>wayyērāʾ ʾĕlōhîm ʾel-yaʿăqōḇ ʿôḏ bĕḇōʾô mippaddan ʾărām wayyĕḇāreḵ ʾōtô</strong> — "God appeared again (<em>ʿôḏ</em>, once more) to Jacob when he came from Paddan Aram and blessed him." <em>ʿôḏ</em> (H5750, again, still, yet more) marks this as the third major theophany in Jacob's narrative: the first at Bethel when fleeing (28:13), the second at Mahanaim/Peniel when returning (32:1,24), and now this third at Bethel. The sequential theophanies frame Jacob's entire Haran sojourn as a period between two Bethel encounters — the departure theophany and the return theophany. The blessing formula reaffirms that the covenant continues despite ch 34's violence.</p>""",
    "10": """<p><strong>wayyōʾmer-lô ʾĕlōhîm šimĕḵā yaʿăqōḇ lōʾ-yiqqārēʾ šimĕḵā ʿôḏ yaʿăqōḇ kî ʾim-yiśrāʾēl yihyeh šĕmeḵā wayyiqrāʾ ʾet-šĕmô yiśrāʾēl</strong> — "Your name is Jacob; your name shall no longer be called Jacob, but Israel shall be your name." The formal name-change uses <em>qārāʾ</em> (to call) three times in this verse — the word's repetition signals the solemnity of the conferral. This is the second divine confirmation of the Peniel name-change (32:28); the repetition at Bethel in the presence of the household gives the name Israel its official covenant status. The formula <em>lōʾ-yiqqārēʾ šimĕḵā ʿôḏ yaʿăqōḇ</em> (you shall no longer be called Jacob) parallels Abraham's name-change formula in 17:5 (no longer called Abram). Yet the narrative continues to use "Jacob" interchangeably with "Israel" — suggesting the name-change is covenantal identity, not erasure of the old.</p>""",
    "11": """<p><strong>wayyōʾmer-lô ʾĕlōhîm ʾănî ʾēl šadday pĕrēh ûrĕḇēh gôy ûqĕhal gôyim yihyeh mimmeḵā ûmĕlāḵîm mēḥălāṣeyḵā yēṣēʾû</strong> — "God said, 'I am El Shaddai — be fruitful and multiply. A nation and a company of nations shall come from you, and kings shall come from your body.'" <em>ʾĒl Šadday</em> (H7706) — the divine name used at the Abrahamic covenant's key ratification (17:1) and the Isaacic blessing on Jacob before his departure to Haran (28:3). Its reappearance here signals that the full covenant is being re-ratified at Bethel. <em>Gôy ûqĕhal gôyim</em> — a singular nation (Israel) and a community/assembly (<em>qāhāl</em>, H6951) of nations — the universal scope of the covenant. <em>Mĕlāḵîm</em> (kings) from Jacob's body anticipates the Davidic monarchy; the same promise was given to Abraham (17:6) and to Rebekah (25:23).</p>""",
    "12": """<p><strong>wĕʾet-hāʾāreṣ ʾăšer nātattî lĕʾaḇrāhām wĕlĕyiṣḥāq lĕḵā ʾetennennāh ûlĕzarʿăḵā ʾaḥăreyḵā ʾettēn ʾet-hāʾāreṣ</strong> — "The land I gave to Abraham and Isaac I give to you, and to your offspring after you I give the land." The threefold repetition of <em>ʾettēn</em> (I give) — past (to Abraham and Isaac), present (to you), and future (to your offspring) — compresses the entire land-covenant into a single verse. This is the fourth explicit land-covenant in Jacob's narrative (28:13; 32:13; 33:17-20 implicitly; 35:12 explicitly). The covenant extends backward to Abraham and forward to Jacob's offspring — the temporal span of the promise encompasses both the patriarchal period and the conquest/settlement narrative of Joshua.</p>""",
    "13": """<p><strong>wayyaʿal mēʿālāyw ʾĕlōhîm bimmāqôm ʾăšer-dibbēr ʾittô</strong> — "God went up from him at the place where he had talked with him." The verb <em>ʿālāh</em> (to ascend, go up) marks the conclusion of the theophany — the divine presence that descended for the encounter now withdraws. The same verb appears at the conclusion of the 17:22 theophany (God went up from Abraham). The ascent formula is the narrative signal that the divine speech act is complete and the covenant has been ratified. The narrator notes the place (<em>bimmāqôm</em>) — the specific geographical site remains theologically charged even after the divine withdrawal.</p>""",
    "14": """<p><strong>wayyaṣṣeḇ yaʿăqōḇ maṣṣēḇāh bammāqôm ʾăšer-dibbēr ʾittô maṣṣeḇet ʾāḇen wayyasseḵ ʿāleyhā nesek wayyiṣṣōq ʿāleyhā šāmen</strong> — "Jacob set up a stone pillar (<em>maṣṣēḇāh</em>) at the place where God spoke with him, and poured a drink offering (<em>nesek</em>) on it and poured oil (<em>šāmen</em>) on it." <em>Maṣṣēḇāh</em> (H4676, standing stone/stele) — Jacob set up the same type of pillar at Bethel during his departure (28:18), where he also poured oil. The return completes the vow: in 28:18-22 he set up the pillar, poured oil, and vowed; now he fulfills the vow with a second anointing. The addition of <em>nesek</em> (H5262, libation/drink offering) — not present in 28:18 — elevates the ritual to a full cultic act, anticipating the Levitical libation system (Num 15:5-10).</p>""",
    "15": """<p><strong>wayyiqrāʾ yaʿăqōḇ ʾet-šēm hammāqôm ʾăšer dibbēr ʾittô šām ʾĕlōhîm bêt-ʾēl</strong> — "Jacob called the name of the place where God spoke with him Bethel." The naming is the second official naming of Bethel — the first was in 28:19 after the ladder-theophany. The repetition confirms the name while emphasizing that the name refers specifically to the speaking of God there (<em>ʾăšer dibbēr ʾittô šām ʾĕlōhîm</em>). The place-name is a permanent theological inscription: this is where God speaks.</p>""",
    "16": """<p><strong>wayyisĕʿû mibbêt-ʾēl wayhî-ʿôḏ kibrat-hāʾāreṣ lāḇôʾ ʾeprātāh waṯṯēled rāḥēl waṯṯĕqaš bĕliddtāh</strong> — "They moved on from Bethel. While still some distance (<em>kibrat-hāʾāreṣ</em>) from Ephrath, Rachel began to give birth and had great difficulty." <em>Kibrat-hāʾāreṣ</em> is a distance unit of uncertain measurement — possibly a few miles; the unit appears only here and in 48:7 (Jacob's repetition of this event). The narrative proximity to Bethel — the theophanic-covenant site — for Rachel's death in childbirth is the tragic counterpoint to the covenant renewal. The covenant is ratified; the beloved dies. <em>Waṯṯĕqaš bĕliddtāh</em> — "she had difficulty (<em>qāšāh</em>, H7185, to be hard/difficult) in her labor."</p>""",
    "17": """<p><strong>wayhî bĕhaqšōtāh bĕliddtāh waṯṯōʾmer lāh hamĕyalledet ʾal-tîrĕʾî kî-gam-zeh lāḵ bēn</strong> — "As she was having great difficulty, the midwife said to her, 'Do not despair (<em>ʾal-tîrĕʾî</em>), for you have another son.'" The midwife's consolation formula <em>ʾal-tîrĕʾî</em> (do not fear) — the same divine consolation formula used throughout the patriarchal narratives (15:1; 21:17; 26:24; 46:3). The midwife administers the covenant-comfort formula in a dying woman's ears. The information "another son" fulfills Rachel's own prayer in 30:24: <em>yōsēp YHWH lî bēn ʾaḥēr</em> (may YHWH add another son). The prayer is answered at the cost of the one who prayed it.</p>""",
    "18": """<p><strong>wayhî bĕṣēʾt napšāh kî mētāh waṯṯiqrāʾ šĕmô ben-ʾônî wĕʾāḇîw qārāʾ-lô binyāmîn</strong> — "As her life was departing — for she was dying — she named him Ben-Oni. But his father named him Benjamin." <em>Ben-ʾônî</em> (H1126) — "son of my sorrow/suffering"; <em>ʾôn</em> or <em>ʾōnî</em> (H205/H4036, trouble, sorrow, iniquity) is Rachel's dying experience. <em>Binyāmîn</em> (H1144) — "son of my right hand" (<em>ben-yāmîn</em>); the right hand is the position of power and favor (Gen 48:13-19; Ps 110:1; Matt 26:64). Jacob's renaming transforms the death-name to a life-name — refusing to allow his son to carry the name of grief. This naming contrast (mother's death-name / father's hope-name) is the most emotionally charged naming episode in Genesis; no other birth involves two names by two different namers at a moment of death.</p>""",
    "19": """<p><strong>waṯṯāmāṯ rāḥēl waṯṯiqqāḇēr bĕḏereḵ ʾeprātāh hîʾ bêt-lāḥem</strong> — "Rachel died and was buried on the road to Ephrath (that is, Bethlehem)." The narrator identifies <em>ʾeprātāh</em> with <em>Bêt-lāḥem</em> (Bethlehem, H1035, "house of bread/food") — a retrospective identification for the reader. Bethlehem will be the city of Boaz and Ruth (Ruth 1:19-22; 4:11), the birthplace of David (1 Sam 16:1; 17:12), and the birthplace of the Messiah (Mic 5:2; Matt 2:1). Rachel's tomb at Bethlehem becomes the site Jeremiah invokes when he prophesies "Rachel weeping for her children" (Jer 31:15) — and which Matthew cites for Herod's massacre of the Bethlehem infants (Matt 2:18). The location of the tomb at Bethlehem ties maternal grief to the city of messianic origin.</p>""",
    "20": """<p><strong>wayyaṣṣeḇ yaʿăqōḇ maṣṣēḇāh ʿal-qĕḇurātāh hîʾ maṣṣeḇet qĕḇurat-rāḥēl ʿaḏ-hayyôm</strong> — "Jacob set up a pillar over her tomb; it is the pillar of Rachel's tomb to this day." Jacob's second use of a <em>maṣṣēḇāh</em> in this chapter (cf. v14 at Bethel) — but now for grief rather than covenant. The pillar at Bethel marked the place of theophany; the pillar at Rachel's tomb marks the place of death. The narrator's editorial note <em>ʿaḏ-hayyôm</em> (to this day) is an antiquarian marker — the tomb was still a known landmark when the narrator wrote. Both Bethel and Rachel's tomb were cultic-memorial sites in Israel's subsequent history.</p>""",
    "21": """<p><strong>wayyisaʿ yiśrāʾēl wayyeṭ ʾohălô mēhāllāh lĕmigdal-ʿēḏer</strong> — "Israel moved on and pitched his tent beyond Migdal Eder." <em>Migdal-ʿēḏer</em> (H4029, "tower of the flock/herd" — <em>migdāl</em> = tower, <em>ʿēḏer</em> = flock) is a location near Bethlehem associated with pastoral watch. Micah 4:8 addresses "O tower of the flock (<em>migdal-ʿēḏer</em>)" in a messianic prophecy about the reign coming to Zion — the proximity to Bethlehem and to Rachel's tomb gives the place messianic-pastoral resonance. The use of <em>yiśrāʾēl</em> rather than <em>yaʿăqōḇ</em> for the subject marks this movement with the covenant name, even in the midst of grief.</p>""",
    "22": """<p><strong>wayhî biškon yiśrāʾēl bāʾāreṣ hahîʾ wayyēleḵ rĕʾûḇen wayyiškaḇ ʾet-bilhāh pîlegeš ʾāḇîw wayyišmaʿ yiśrāʾēl</strong> — "Reuben went and lay with Bilhah his father's concubine, and Israel heard of it." Reuben's act — <em>šāḵaḇ ʾet-pîlegeš ʾāḇîw</em> (lay with his father's concubine) — is a sexual power-claim in the ANE inheritance tradition: taking the father's concubine signals a bid for household authority (cf. Absalom's seizure of David's concubines in 2 Sam 16:21-22 as a political usurpation; 2 Sam 12:8; 1 Kgs 2:22). The act forfeits Reuben's firstborn birthright — confirmed in Gen 49:3-4 ("you went up to your father's bed") and 1 Chron 5:1-2 (his birthright was transferred to the sons of Joseph). Lev 18:8 and 20:11 prohibit this as a violation of the father. <em>Wayyišmaʿ yiśrāʾēl</em> — "Israel heard it" — the same verb (<em>šāmaʿ</em>) as the name Simeon; the father hears and says nothing immediately.</p>""",
    "23": """<p><strong>bĕnê lēʾāh bĕḵôr yaʿăqōḇ rĕʾûḇen wĕšimʿôn wĕlēwî wîhûḏāh wĕyiśśāḵār wûzĕḇûlûn</strong> — "The sons of Leah: Reuben Jacob's firstborn, Simeon, Levi, Judah, Issachar, and Zebulun." The twelve-sons enumeration (vv23-26) is the first complete listing of the tribal fathers in a single context. The order follows maternal grouping rather than birth order: Leah's six first, then Rachel's two, then the maidservants' four. <em>Bĕḵôr yaʿăqōḇ</em> (Jacob's firstborn) — Reuben's status is noted even as the narrative has just recorded the act that will cost him this status (v22). The irony is structural: Reuben is named as firstborn immediately after his birthright is forfeited.</p>""",
    "24": """<p><strong>bĕnê rāḥēl yôsēp ûḇinyāmîn</strong> — "The sons of Rachel: Joseph and Benjamin." The brevity of Rachel's entry — two names, no elaboration — after her death in vv18-20 is a deliberate narrative economy. The two named are the youngest of Jacob's sons by age; their placement last among the born-in-Canaan/Haran listing (Benjamin was just born in v18) signals their narrative significance: Joseph will dominate chs 37-50, Benjamin will be the pivot of the Joseph-brothers reconciliation.</p>""",
    "25": """<p><strong>ûḇĕnê bilhāh šipĕḥat rāḥēl dān wĕnaptālî</strong> — "The sons of Bilhah, Rachel's servant: Dan and Naphtali." Dan and Naphtali are identified through Bilhah's relationship to Rachel (not to Jacob directly), maintaining the surrogate-mother legal structure established in ch 30. Their placement before Zilpah's sons (Gad and Asher) follows the order of the surrogate births in ch 30 — Bilhah's children came first.</p>""",
    "26": """<p><strong>ûḇĕnê zilpāh šipĕḥat lēʾāh gāḏ wĕʾāšēr ʾēlleh bĕnê yaʿăqōḇ ʾăšer yullad-lô bĕpaddan ʾărām</strong> — "The sons of Zilpah, Leah's servant: Gad and Asher. These are the sons of Jacob who were born to him in Paddan Aram." The closing formula <em>ʾăšer yullad-lô bĕpaddan ʾărām</em> is technically imprecise — Benjamin was born in Canaan (v18), not Paddan Aram — which the narrator is aware of (having just recorded it). This may be a summary formula for the entire list (most were born in Paddan Aram) rather than an assertion about each individual, or a scribal tradition that preserves the Paddan Aram origin of the tribal system.</p>""",
    "27": """<p><strong>wayyāḇōʾ yaʿăqōḇ ʾel-yiṣḥāq ʾāḇîw mamrĕʾāh qiryat hāʾarbaʿ hîʾ ḥeḇrôn ʾăšer-gār-šām ʾaḇrāhām wĕyiṣḥāq</strong> — "Jacob came to his father Isaac at Mamre — Kiriath Arba (that is, Hebron) — where Abraham and Isaac had stayed." The identification of Mamre with <em>Qiryat hāʾarbaʿ</em> (city of Arba, H7153, later Hebron) follows the same narrative convention as the Bethel/Luz and Ephrath/Bethlehem identifications earlier in this chapter. Jacob's return to Mamre/Hebron closes the geographic arc that began when he fled to Haran (28:1-5): he returns to his father's house, fulfilling the Bethel vow condition (28:21: "if I return safely to my father's house").</p>""",
    "28": """<p><strong>wayhî yĕmê yiṣḥāq mĕʾat šānāh wĕšmōnîm šānāh</strong> — "Isaac lived 180 years." The patriarchal age formula provides the numerical data for the genealogical record. Isaac's 180 years: he was born when Abraham was 100 (21:5), making him 60 when Jacob and Esau were born (25:26), 100 when Jacob fled to Haran, and approximately 120 when Jacob returned. The 180 years places Isaac's death after Jacob's return but before Joseph's Egyptian career begins — Isaac is alive through ch 35 but not beyond. Abraham lived 175 years (25:7), Isaac 180, Jacob 147 (47:28) — a descending series in the covenant generations, consistent with the post-flood lifespan pattern.</p>""",
    "29": """<p><strong>wayyigwaʿ yiṣḥāq wayyāmāt wayyēʾāsep ʾel-ʿammāyw zāqēn ûśĕḇaʿ yāmîm wayyiqbĕrû ʾōtô ʿēśāw wĕyaʿăqōḇ bānāyw</strong> — "Isaac breathed his last and died, and was gathered to his people (<em>wayye'aseph el-ammav</em>), old and full of days; and Esau and Jacob buried him." <em>Wayyigwaʿ</em> (Qal of <em>gāwaʿ</em>, H1478, to breathe one's last, to expire) + <em>wayyāmāt</em> (to die) — the double death formula used for Abraham (25:8) and for Jacob (49:33). <em>Wayye'aseph el-ammav</em> (gathered to his people) — the covenant afterlife formula; death is entrance into the community of the covenant dead. The burial by both sons — Esau and Jacob together — is the narrative counterpart to Ishmael and Isaac burying Abraham (25:9). The estranged sons are reconciled at the patriarch's death. Isaac's death at 180, with both sons present, is the covenant patriarch's death formula: full lifespan, gathered to his people, buried by his sons.</p>"""
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_ORIGINAL)
    save_comm('mkt-original', 'genesis', existing)

    result = load_comm('mkt-original', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [33, 34, 35]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis total: {total_chs} chapters, {total_vv} verses with original data')
    print('Genesis 33-35 mkt-original written.')

if __name__ == '__main__':
    main()
